            if dot_width < 0:
                dot_width = 0

        cell_width = (dot_width + 1) // 2

        # Build cells
        cells = bytearray()
        for c in range(cell_width):
            bits = 0
            # Dot positions: (row_within_cell, col_within_cell) -> bit index
            # row=0,col=0 -> bit 0 (dot 1)
            # row=1,col=0 -> bit 1 (dot 2)
            # row=2,col=0 -> bit 2 (dot 3)
            # row=0,col=1 -> bit 3 (dot 4)
            # row=1,col=1 -> bit 4 (dot 5)
            # row=2,col=1 -> bit 5 (dot 6)
            # row=3,col=0 -> bit 6 (dot 7)
            # row=3,col=1 -> bit 7 (dot 8)
            for dr in range(4):  # dot row within cell
                for dc in range(2):  # dot col within cell
                    dot_col_global = c * 2 + dc
                    if dot_col_global >= dot_width:
                        continue
                    # Sample input col
                    if H == 0 or math.isnan(H):
                        continue
                    if math.isinf(H):
                        input_col = 0
                    else:
                        input_col = int(math.floor(dot_col_global / H))
                    # Check if any line at this dot row has the col in its span
                    on = False
                    for i in lines_here:
                        if line_dot_row_within[i] != dr:
                            continue
                        first, last, _ = line_info[i]
                        if first is None:
                            continue
                        if first <= input_col <= last:
